/* == EXEMPLE: retry puis abandon ======================== */
int example_retry_open(const char *path, int retries) {
    for (int i = 0; i < retries; i++) {
        int fd = open(path, O_RDONLY);
        if (fd >= 0) return fd;
        if (errno != EINTR) return -1;
    }
    return -1;
}

